def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}
    qty = int(params.get("qty", 1) or 1)
    if qty < 1:
        qty = 1
    PRICE_FLOOR = 1.0

    if name == "emit":
        # Emitting a tonne adds compliance demand; scarcity drifts the price up.
        s["emissions"] = int(s["emissions"]) + qty
        s["price"] = round(float(s["price"]) + 0.5 * qty, 4)

    elif name == "buy_credit":
        # Buy one allowance at a time while the market has supply and cash covers
        # it; each purchase nudges the price up with demand.
        for _ in range(qty):
            price = float(s["price"])
            if int(s["market_supply"]) > 0 and float(s["cash"]) >= price:
                s["credits"] = int(s["credits"]) + 1
                s["cash"] = round(float(s["cash"]) - price, 4)
                s["market_supply"] = int(s["market_supply"]) - 1
                s["price"] = round(price + 1.0, 4)
            else:
                break

    elif name == "sell_credit":
        # Sell held allowances back; added supply softens the price (to a floor).
        for _ in range(qty):
            if int(s["credits"]) > 0:
                price = float(s["price"])
                s["credits"] = int(s["credits"]) - 1
                s["cash"] = round(float(s["cash"]) + price, 4)
                s["market_supply"] = int(s["market_supply"]) + 1
                s["price"] = round(max(PRICE_FLOOR, price - 1.0), 4)
            else:
                break

    elif name == "retire":
        # Permanently surrender held allowances for compliance; retired credits
        # leave circulation forever, tightening effective supply.
        for _ in range(qty):
            if int(s["credits"]) > 0:
                s["credits"] = int(s["credits"]) - 1
                s["retired"] = int(s["retired"]) + 1
                s["price"] = round(float(s["price"]) + 0.5, 4)
            else:
                break

    # Recompute the compliance invariants after every step. A firm is compliant
    # only when every emitted tonne is covered by a retired allowance AND
    # cumulative emissions stay within the regulatory cap.
    s["uncovered"] = max(0, int(s["emissions"]) - int(s["retired"]))
    s["over_cap"] = max(0, int(s["emissions"]) - int(s["cap"]))
    s["compliant"] = bool(s["uncovered"] == 0 and s["over_cap"] == 0)
    return s

