def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip().lower()
            v = v.strip()
            if k in ('price', 'market_supply', 'cap'):
                try:
                    out[k] = float(v) if k == 'price' else int(float(v))
                except ValueError:
                    pass
    return out
